n = metadata["num_input_qubits"]
s_val = int(metadata["hidden_period"], 2)

# Group measured input states by their corresponding output register values
# Based on the probe circuit: bits 0 to n-1 are input, bits n to 2n-1 are output
# Qiskit bitstring order is 'q_{2n-1} ... q_0', so output is b[0:n], input is b[n:2n]
groups = {}
for bitstring in counts:
    out_val = bitstring[:n]
    in_val = int(bitstring[n:], 2)
    if out_val not in groups:
        groups[out_val] = set()
    groups[out_val].add(in_val)

for out_val, inputs in groups.items():
    # Simon's algorithm ensures each output corresponds to exactly two inputs {x, x ^ s}
    assert len(inputs) <= 2, f"Output register {out_val} associated with too many inputs: {inputs}"
    if len(inputs) == 2:
        vals = list(inputs)
        assert vals[0] ^ vals[1] == s_val, f"Inputs {vals} for output {out_val} do not XOR to hidden period {s_val}"
